  "Porsche Cayenne": ["DIESEL PLATINUM EDITION"],
  "Toyota Corolla": ["H3 G 1.8"],
  "Mahindra E VERITO": ["D2"],
  "CITROEN Basalt": ["Max 1.2 Turbo Petrol MT"],
  "Mahindra Quanto": ["C4", "C6", "C8"],
  "Volvo V 40": ["D3 R design"],
  "Jaguar F- PACE": ["PRESTIGE 2.0 DIESEL"],
  "Nissan Evalia": ["XV"],
  "Fiat PUNTO PURE": ["1.3 MULTIJET"],
  "Toyota HILUX": ["STD 4X4 MT"],
  "Renault Fluence": ["1.5 E2"],
  "Force Motors GURKHA": ["4x4", "4x4x4"],
  "Jaguar XJ L": ["2.0 PORTFOLIO PETROL", "3.0 V 6 PORTFOLIO"],
  "Mercedes Benz M Class": ["ML 250 CDI"],
  "Toyota INNOVA HYCROSS": ["ZX HYBRID 7 STR"],
  "Maruti Invicto": ["ALPHA PLUS 7 STRONG HYBRID"],
  "BMW 1 Series": ["118D HATCHBACK"],
  "Landrover Discovery 4": ["3.0 V6 SE"],
  "Mercedes Benz S Class": ["500L", "S350 CDI", "S350d"],
  "BMW Z4": ["ROADSTAR SDRIVE 35I"],
  "Mercedes Benz CLS Class": ["CLS 250 CDI"],
