const allYears = ["2025", "2024", "2023", "2022", "2021", "2020", "2019", "2018", "2017", "2016", "2015", "2014", "2013", "2012", "2011", "2010", "2009", "2008", "2007", "2006", "2005", "2001"];
const fuelTypes = ["CNG", "Diesel", "Electric", "Hybrid", "Petrol"];
const transmissionTypes = ["Auto", "Manual"];
const ownershipTypes = ["10th owner", "1st owner", "2nd owner", "3rd owner", "4th owner", "5th owner", "6th owner", "7th owner", "8th owner"];
const kmRanges = ["0 - 25,000 KM","25,001 - 50,000 KM","50,001 - 75,000 KM","75,001 - 1,10,000 KM","1,10,001 - 1,50,000 KM","1,50,000+ KM"];
const cities = ["Agartala","Agra","Ahmedabad","Ajmer","Aligarh","Allahabad","Amritsar","Aurangabad","Bangalore","Bareilly","Bhopal","Bhubaneswar","Chandigarh","Chennai","Coimbatore","Dehradun","Delhi","Faridabad","Ghaziabad","Gurgaon","Guwahati","Hyderabad","Indore","Jaipur","Jalandhar","Jammu","Jodhpur","Kanpur","Kochi","Kolkata","Lucknow","Ludhiana","Madurai","Mangalore","Mumbai","Mysore","Nagpur","Nashik","Noida","Patna","Pune","Raipur","Rajkot","Ranchi","Surat","Thiruvananthapuram","Udaipur","Vadodara","Varanasi","Visakhapatnam"];

function AutocompleteInput({ label, value, onChange, options, placeholder, disabled }) {
  const [query, setQuery] = useState(value || "");
  const [open, setOpen] = useState(false);
  const [dropPos, setDropPos] = useState({ top: 0, left: 0 });
  const ref = useRef();
  const inputRef = useRef();

  useEffect(() => { setQuery(value || ""); }, [value]);
  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const calcPos = () => {
    if (inputRef.current) {
      const rect = inputRef.current.getBoundingClientRect();
      setDropPos({ top: rect.top, left: rect.right + 10 });
    }
  };

  const filtered = options.filter(o => o.toLowerCase().includes(query.toLowerCase()));
  const handleSelect = (val) => { setQuery(val); onChange(val); setOpen(false); };
  const handleInput = (e) => { setQuery(e.target.value); onChange(""); calcPos(); setOpen(true); };

  return (
    <div className="field-group" ref={ref} style={{ position: "relative" }}>
      <label className="field-label">{label} <span className="required-star">*</span></label>
      <input ref={inputRef} className="autocomplete-input" type="text" value={query}
        onChange={handleInput}
        onFocus={() => { if (!disabled) { calcPos(); setOpen(true); } }}
        placeholder={disabled ? "Select previous field first" : placeholder}
        disabled={disabled} autoComplete="off"
      />
      {open && (
        <ul className="autocomplete-dropdown" style={{ top: dropPos.top, left: dropPos.left, position: "fixed" }}>
          {filtered.length > 0
            ? filtered.map((opt, i) => <li key={i} className="autocomplete-item" onMouseDown={() => handleSelect(opt)}>{opt}</li>)
            : <li className="autocomplete-item-empty">No results found</li>
          }
        </ul>
      )}
    </div>
  );
}

function SideSelect({ label, name, value, onChange, options, placeholder, required }) {
  const [open, setOpen] = useState(false);
  const [dropPos, setDropPos] = useState({ top: 0, left: 0 });
  const ref = useRef();
  const btnRef = useRef();

  useEffect(() => {
    const handler = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleOpen = () => {
    if (btnRef.current) {
      const rect = btnRef.current.getBoundingClientRect();
      setDropPos({ top: rect.top, left: rect.right + 10 });
    }
    setOpen(!open);
  };

  const handleSelect = (val) => { onChange({ target: { name, value: val } }); setOpen(false); };

  return (
    <div className="field-group" ref={ref} style={{ position: "relative" }}>
      {label && <label className="field-label">{label} {required && <span className="required-star">*</span>}</label>}
      <button type="button" ref={btnRef} className="side-select-btn" onClick={handleOpen}>
        <span style={{ color: value ? "#111827" : "#6b7280" }}>{value || placeholder}</span>
        <span style={{ color: "#6b7280" }}>▾</span>
      </button>
      {open && (
        <ul className="autocomplete-dropdown" style={{ top: dropPos.top, left: dropPos.left, position: "fixed" }}>
          {options.map((opt, i) => (
            <li key={i} className="autocomplete-item"
              style={{ fontWeight: opt === value ? "bold" : "normal", color: opt === value ? "#60a5fa" : "#e2e8f0" }}
              onMouseDown={() => handleSelect(opt)}>
              {opt === value ? "✓ " : ""}{opt}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

function Prediction() {
  const navigate = useNavigate();
  const { setPredictionData } = useCarData();
  const [error, setError] = useState("");
  const [locationLoading, setLocationLoading] = useState(false);
  const [rcFileName, setRcFileName] = useState("");
  const [rcError, setRcError] = useState("");

  const [carData, setCarData] = useState({
    brand:"", carModel:"", variant:"", year:"", fuel:"",
    transmission:"", kmDriven:"", ownership:"", location:"",
    electricRange:"", batteryCapacity:"", insurance:"", rcCard:null,
  });

  const isElectric = carData.fuel === "Electric";
  const availableModels = carData.brand ? (modelsByBrand[carData.brand] || []) : [];
  const availableVariants = carData.carModel ? (variantsByModel[carData.carModel] || []) : [];

  const isFormComplete = () => {
    const base = carData.brand && carData.carModel && carData.variant &&
      carData.year && carData.fuel && carData.transmission &&
      carData.kmDriven && carData.ownership && carData.location &&
      carData.insurance && carData.rcCard;
    if (isElectric) return base && carData.electricRange && carData.batteryCapacity;
    return base;
  };

  const setField = (field) => (val) => setCarData((p) => ({
    ...p, [field]: val,
    ...(field === "brand" ? { carModel:"", variant:"" } : {}),
    ...(field === "carModel" ? { variant:"" } : {}),
  }));

  const handleChange = (e) => setCarData((p) => ({ ...p, [e.target.name]: e.target.value }));

  const handleRCUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const allowed = ["image/jpeg","image/png","image/jpg","application/pdf"];
    if (!allowed.includes(file.type)) {
      setRcError("❌ Invalid file. Please upload JPG/PNG or PDF only.");
      setRcFileName(""); setCarData((p) => ({...p,rcCard:null})); e.target.value=""; return;
    }
    const n = file.name.toLowerCase();
    const rcKw = ["rc","registration","regn","reg_cert","rc_card","rc-card","vehicle_reg","vehicle_registration"];
    const badKw = ["aadhar","aadhaar","pan","passport","license","dl","driving","voter","invoice","birth","salary","bank","statement","resume","cv"];
    if (badKw.some(k => n.includes(k))) {
      setRcError(`❌ "${file.name}" is not an RC Card. Please upload your Vehicle Registration Certificate.`);
      setRcFileName(""); setCarData((p) => ({...p,rcCard:null})); e.target.value=""; return;
    }
    if (!rcKw.some(k => n.includes(k))) {
      setRcError("⚠️ Could not confirm this is an RC Card. Make sure you upload your Vehicle Registration Certificate.");
      setCarData((p) => ({...p,rcCard:file})); setRcFileName(file.name); return;
    }
    setRcError(""); setCarData((p) => ({...p,rcCard:file})); setRcFileName(file.name);
  };

  const handleCurrentLocation = () => {
    if (!navigator.geolocation) { alert("Geolocation not supported."); return; }
    setLocationLoading(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${pos.coords.latitude}&lon=${pos.coords.longitude}&format=json&accept-language=en`);
          const data = await res.json();
          const city = data.address.city || data.address.town || data.address.village || data.address.suburb || data.address.county || "Unknown";
          setCarData((p) => ({ ...p, location: city }));
          alert(`📍 Location detected: ${city}`);
        } catch {
          setCarData((p) => ({ ...p, location: `${pos.coords.latitude.toFixed(4)},${pos.coords.longitude.toFixed(4)}` }));
        }
        setLocationLoading(false);
      },
      (err) => {
        setLocationLoading(false);
        if (err.code === 1) alert("❌ Location permission denied. Allow location access in browser settings.");
        else alert("❌ Unable to get location. Please select manually.");
      },
      { timeout: 10000, enableHighAccuracy: true }
    );
  };

  const handleReset = () => {
    setCarData({ brand:"",carModel:"",variant:"",year:"",fuel:"",transmission:"",kmDriven:"",ownership:"",location:"",electricRange:"",batteryCapacity:"",insurance:"",rcCard:null });
    setRcFileName(""); setRcError(""); setError("");
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!isFormComplete()) { setError("⚠ Please fill all required fields before predicting the car price."); return; }
    setError("");
    setPredictionData(carData);
    navigate("/result");
  };

  const locationOptions = [...cities, ...(carData.location && !cities.includes(carData.location) && carData.location !== "" ? [carData.location] : [])];

  return (
    <div className="prediction-container">
      <h1>Used Car Price Prediction</h1>
      <form className="prediction-form" onSubmit={handleSubmit}>
        {error && <p className="error-message">{error}</p>}

        <AutocompleteInput label="Brand" value={carData.brand} onChange={setField("brand")} options={allBrands} placeholder="Type brand e.g. Maruti, Hyundai..." />
        <AutocompleteInput label="Car Model" value={carData.carModel} onChange={setField("carModel")} options={availableModels} placeholder="Type model e.g. Maruti Swift..." disabled={!carData.brand} />
        <AutocompleteInput label="Car Variant" value={carData.variant} onChange={setField("variant")} options={availableVariants} placeholder="Type variant e.g. ZXI, VXI..." disabled={!carData.carModel} />
        <AutocompleteInput label="Year" value={carData.year} onChange={setField("year")} options={allYears} placeholder="Type year e.g. 2020" />

        <SideSelect label="Fuel Type" name="fuel" value={carData.fuel} onChange={handleChange} placeholder="Select Fuel Type" required options={fuelTypes} />

        {isElectric && (
          <div className="electric-section">
            <div className="electric-badge">⚡ Electric Vehicle Details</div>
            <SideSelect label="Electric Range (km)" name="electricRange" value={carData.electricRange} onChange={handleChange} placeholder="Select Range" required options={["0 - 150 km","150 - 300 km","300 - 450 km","450+ km"]} />
            <SideSelect label="Battery Capacity (kWh)" name="batteryCapacity" value={carData.batteryCapacity} onChange={handleChange} placeholder="Select Capacity" required options={["Below 30 kWh","30 - 50 kWh","50 - 75 kWh","75+ kWh"]} />
          </div>
        )}

        <SideSelect label="Transmission" name="transmission" value={carData.transmission} onChange={handleChange} placeholder="Select Transmission" required options={transmissionTypes} />
        <SideSelect label="KM Driven" name="kmDriven" value={carData.kmDriven} onChange={handleChange} placeholder="Select KM Driven" required options={kmRanges} />
        <SideSelect label="No. of Owners" name="ownership" value={carData.ownership} onChange={handleChange} placeholder="Select Ownership" required options={ownershipTypes} />
        <SideSelect label="Insurance Status" name="insurance" value={carData.insurance} onChange={handleChange} placeholder="Select Insurance" required options={["Valid (Comprehensive)","Valid (Third Party)","Expired","No Insurance"]} />

        <div className="field-group">
          <label className="field-label">Location <span className="required-star">*</span></label>
          <div className="location-row">
            <div style={{ flex: 1 }}>
              <SideSelect name="location" value={carData.location} onChange={handleChange} placeholder="Select Location" options={locationOptions} />
            </div>
            <button type="button" className="location-btn" onClick={handleCurrentLocation} disabled={locationLoading}>
              {locationLoading ? "Detecting..." : "📍 Use Current Location"}
            </button>
          </div>
        </div>

        <div className="field-group">
          <label className="field-label">RC Card (Registration Certificate) <span className="required-star">*</span></label>
          <label className="rc-upload-label">
            <input type="file" accept="image/*,application/pdf" onChange={handleRCUpload} className="rc-upload-input" />
            <span className="rc-upload-btn">📄 {rcFileName || "Upload RC Card"}</span>
          </label>
          {rcError && <p className={rcError.startsWith("⚠️") ? "rc-warning" : "rc-error"}>{rcError}</p>}
          {!rcError && rcFileName && <p className="rc-success">✅ RC Card uploaded successfully</p>}
        </div>

        <p className="required-note"><span className="required-star">*</span> Required fields</p>

        <div className="button-group">
          <button type="submit" className={isFormComplete() ? "btn-predict" : "btn-predict btn-predict-disabled"} disabled={!isFormComplete()}>
            {isFormComplete() ? "🔍 Predict Price" : "🔒 Predict Price"}
          </button>
          <button type="button" onClick={handleReset} className="btn-reset">Reset</button>
        </div>
      </form>
    </div>
  );
}

export default Prediction;
